import { useState } from 'react'
import {
  useFilterStore,
  type Category,
  type WordClass,
  type Difficulty,
  type MasteryStatus,
  type Direction
} from '@/store/useFilterStore'

// FilterBar laut CLAUDE.md §7 — auf jedem Spielmodus-Screen oben einklappbar.
// Auf Home zeigt sie den aktuellen Filter-State (Read-only-Übersicht), aber
// auch von hier aus änderbar.
//
// UI: Compact-Mode (zeigt aktive Filter als Chips) + Expand-Modus (4 Selects).

const CATEGORY_LABELS: Record<Category, string> = {
  all: 'Alle',
  anamnese: 'Anamnese',
  anatomie: 'Anatomie',
  symptome: 'Symptome',
  krankheiten: 'Krankheiten',
  pharma: 'Pharma',
  untersuchung: 'Untersuchung',
  gynaekologie: 'Gynäkologie',
  verb: 'Verben',
  adjektiv: 'Adjektive',
  phrase: 'Phrasen'
}

const WORDCLASS_LABELS: Record<WordClass, string> = {
  all: 'Alle Wortarten',
  noun: 'Substantive',
  verb: 'Verben',
  adjective: 'Adjektive',
  phrase: 'Phrasen',
  question: 'Fragen'
}

const DIFFICULTY_LABELS: Record<Difficulty, string> = {
  all: 'Alle Schwierigkeiten',
  easy: 'Leicht (1–2)',
  medium: 'Mittel (3)',
  hard: 'Schwer (4–5)'
}

const MASTERY_LABELS: Record<MasteryStatus, string> = {
  all: 'Alle',
  unmastered: 'Nicht gemeistert',
  mastered: 'Gemeistert',
  production_mastered: 'Production-mastered'
}

export function FilterBar() {
  const [open, setOpen] = useState(false)
  const f = useFilterStore()

  const activeCount =
    (f.category !== 'all' ? 1 : 0) +
    (f.wordClass !== 'all' ? 1 : 0) +
    (f.difficulty !== 'all' ? 1 : 0) +
    (f.mastery !== 'all' ? 1 : 0) +
    (f.direction !== 'hu_to_de' ? 1 : 0)

  return (
    <div
      style={{
        background: 'var(--white)',
        border: '2px solid var(--green)',
        borderRadius: 12,
        padding: open ? '0.85rem 1rem' : '0.55rem 0.9rem',
        boxShadow: 'var(--shadow-card)',
        transition: 'padding 120ms'
      }}
    >
      <button
        onClick={() => setOpen((o) => !o)}
        style={{
          background: 'none',
          border: 'none',
          padding: 0,
          width: '100%',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          cursor: 'pointer',
          fontFamily: 'inherit',
          fontSize: '0.9rem',
          color: 'inherit'
        }}
        aria-expanded={open}
      >
        <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span aria-hidden="true">🎛️</span>
          <span style={{ fontWeight: 600 }}>Filter</span>
          {activeCount > 0 && (
            <span
              style={{
                background: 'var(--red)',
                color: 'var(--cream)',
                fontSize: '0.7rem',
                padding: '1px 7px',
                borderRadius: 10,
                fontWeight: 700
              }}
            >
              {activeCount}
            </span>
          )}
        </span>
        <span style={{ opacity: 0.5, fontSize: '0.85rem' }}>{open ? '▲' : '▼'}</span>
      </button>

      {open && (
        <div style={{ display: 'grid', gap: '0.7rem', marginTop: '0.9rem' }}>
          {/* Direction-Toggle als Pills oben — der wichtigste Filter beim Lernen */}
          <div>
            <div style={{ fontSize: '0.75rem', fontWeight: 600, opacity: 0.65, letterSpacing: '0.3px', marginBottom: 6 }}>
              Abfrage-Richtung
            </div>
            <div style={{ display: 'flex', gap: 4, padding: 3, background: 'var(--cream)', border: '1.5px solid var(--green)', borderRadius: 999, width: 'fit-content' }}>
              <DirectionPill active={f.direction === 'hu_to_de'} onClick={() => f.setDirection('hu_to_de' as Direction)}>🇭🇺 → 🇩🇪</DirectionPill>
              <DirectionPill active={f.direction === 'de_to_hu'} onClick={() => f.setDirection('de_to_hu' as Direction)}>🇩🇪 → 🇭🇺</DirectionPill>
            </div>
          </div>

          <Select
            label="Kategorie"
            value={f.category}
            onChange={(v) => f.setCategory(v as Category)}
            options={Object.entries(CATEGORY_LABELS)}
          />
          <Select
            label="Wortart"
            value={f.wordClass}
            onChange={(v) => f.setWordClass(v as WordClass)}
            options={Object.entries(WORDCLASS_LABELS)}
          />
          <Select
            label="Schwierigkeit"
            value={f.difficulty}
            onChange={(v) => f.setDifficulty(v as Difficulty)}
            options={Object.entries(DIFFICULTY_LABELS)}
          />
          <Select
            label="Mastery"
            value={f.mastery}
            onChange={(v) => f.setMastery(v as MasteryStatus)}
            options={Object.entries(MASTERY_LABELS)}
          />
          {activeCount > 0 && (
            <button
              onClick={f.reset}
              style={{
                background: 'none',
                border: '1.5px solid var(--red)',
                color: 'var(--red)',
                padding: '0.45rem',
                borderRadius: 8,
                fontFamily: 'inherit',
                fontSize: '0.8rem',
                fontWeight: 600,
                cursor: 'pointer'
              }}
            >
              Zurücksetzen
            </button>
          )}
        </div>
      )}
    </div>
  )
}

function DirectionPill({ active, onClick, children }: { active: boolean; onClick: () => void; children: React.ReactNode }) {
  return (
    <button
      onClick={onClick}
      style={{
        background: active ? 'var(--green)' : 'transparent',
        color: active ? 'var(--cream)' : 'var(--green)',
        border: 'none',
        padding: '0.4rem 0.85rem',
        borderRadius: 999,
        fontFamily: 'inherit',
        fontWeight: 700,
        fontSize: '0.78rem',
        cursor: 'pointer',
        letterSpacing: '0.3px'
      }}
    >
      {children}
    </button>
  )
}

function Select({
  label,
  value,
  onChange,
  options
}: {
  label: string
  value: string
  onChange: (v: string) => void
  options: [string, string][]
}) {
  return (
    <label style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
      <span style={{ fontSize: '0.75rem', fontWeight: 600, opacity: 0.65, letterSpacing: '0.3px' }}>
        {label}
      </span>
      <select
        value={value}
        onChange={(e) => onChange(e.target.value)}
        style={{
          padding: '0.5rem 0.7rem',
          borderRadius: 8,
          border: '1.5px solid rgba(0,0,0,0.15)',
          fontFamily: 'inherit',
          fontSize: '0.9rem',
          background: 'var(--white)'
        }}
      >
        {options.map(([key, label]) => (
          <option key={key} value={key}>
            {label}
          </option>
        ))}
      </select>
    </label>
  )
}
